# Worker thread to fetch schedule without blocking UI
class FetchScheduleWorker(QThread):
    result = Signal(object)
    error = Signal(str)

    def __init__(self, year, parent=None):
        super().__init__(parent)
        self.year = year

    def run(self):
        try:
            # enable cache if available in project
            try:
                from src.f1_data import enable_cache
                enable_cache()
            except Exception:
                pass
            events = get_race_weekends_by_year(self.year)
            self.result.emit(events)
        except Exception as e:
            self.error.emit(str(e))


class FetchMultiYearScheduleWorker(QThread):
    result = Signal(object)
    error = Signal(str)

    def __init__(self, years, parent=None):
        super().__init__(parent)
        self.years = years

    def run(self):
        try:
            try:
                from src.f1_data import enable_cache
                enable_cache()
            except Exception:
                pass
            all_events = []
            for year in self.years:
                events = get_race_weekends_by_year(year)
                for event in events:
                    event["year"] = year
                all_events.extend(events)
            self.result.emit(all_events)
        except Exception as e:
            self.error.emit(str(e))

